func ip(n int) *int { return &n }

// levelOrderP returns a level-order slice of the tree with nil for nil nodes.
func levelOrderP(root *TreeNode) []*int {
	if root == nil {
		return []*int{}
	}
	result := []*int{}
	queue := []*TreeNode{root}
	for len(queue) > 0 {
		node := queue[0]
		queue = queue[1:]
		if node == nil {
			result = append(result, nil)
		} else {
			result = append(result, ip(node.Val))
			queue = append(queue, node.Left, node.Right)
		}
	}
	// trim trailing nils
	for len(result) > 0 && result[len(result)-1] == nil {
		result = result[:len(result)-1]
	}
	return result
}

